insert into public.activities (title, description, location_text, location_url, lat, lng, type, age_range, area, cost, vibes, why_its_worth_it, what_to_watch_out_for, tips, nearby_food, start_date, end_date, recurrence, image_url) values

(
  'IslandWood (Bainbridge Island)',
  'A 255-acre environmental learning center on Bainbridge Island with forest trails, a lookout tower, and a treehouse with canyon views. Trails open to the public on monthly Community Event days — usually free, usually the first Sunday.',
  '4450 Blakely Ave NE, Bainbridge Island, WA 98110',
  'https://maps.google.com/?q=IslandWood+Bainbridge+Island',
  47.5892, -122.5272,
  'activity',
  '{"All Ages", "Toddler", "3-5", "5+", "8+"}',
  'Wider PNW',
  'Free',
  '{"Outdoor / Nature", "Special / Treat", "Chill / Easy"}',
  'IslandWood is normally a private environmental education campus — the only way in as a regular visitor is on their Community Event days (roughly one Sunday a month). That makes it feel like getting a backstage pass. The trails wind through 255 acres of forest to two highlights kids go nuts for: a wooden lookout tower and a treehouse with a canyon view. Pair it with the Seattle–Bainbridge ferry and you''ve got a full-day adventure that costs almost nothing. Lower-key than the zoo or aquarium, with the same wow moments for little kids.',
  '{"Not open daily — trails are public only on Community Event days (usually first Sunday of the month). Check IslandWood''s calendar before you go", "~45 min drive plus a 35-min ferry ride from Seattle — this is a half-to-full-day commitment", "No pets allowed on campus", "Trails have roots and stairs — not stroller-friendly; use a soft carrier for babies/toddlers", "Events fill up — arrive early for parking and to beat the rush to the treehouse"}',
  'Take the Seattle–Bainbridge ferry as foot passengers if you can swing it — Kitsap Transit''s #98 bus runs to IslandWood on Community Event days. Otherwise drive on; it''s ~20 min from the ferry terminal. Pack a picnic and eat outside. Don''t miss the canopy treehouse and the lookout tower — they''re the whole point.',
  '[{"name": "Bainbridge Bakers", "description": "Pre-ferry stop for pastries near the ferry terminal on the Bainbridge side"}, {"name": "Cafe Hitchcock", "description": "Family-friendly lunch spot in Winslow"}, {"name": "Mora Iced Creamery", "description": "Iconic Bainbridge ice cream — post-hike reward"}, {"name": "Pack a picnic", "description": "IslandWood has beautiful meadow and forest spots for eating outside; limited food on-site"}]',
  null, null, null,
  null
),

(
  'Day Out with Thomas (Snoqualmie)',
  'Ride a real train pulled by Thomas the Tank Engine at the Northwest Railway Museum, plus Thomas-themed activities, storytelling, Sir Topham Hatt photo ops, and museum exhibit access. Runs three weekends each July.',
  'Snoqualmie Depot, 38625 SE King Street, Snoqualmie, WA 98065',
  'https://maps.google.com/?q=Northwest+Railway+Museum+Snoqualmie+Depot',
  47.5284, -121.8251,
  'event',
  '{"Toddler", "3-5", "5+"}',
  'Eastside',
  '$$',
  '{"Special / Treat", "Chill / Easy"}',
  'For a train-obsessed kid, this is the event. You board a real vintage train pulled by Thomas himself for a ~25-minute ride, then spend the rest of the visit rotating through storytelling tents, temporary tattoos, lawn games, museum exhibits, and photo ops with Sir Topham Hatt. The Snoqualmie Depot setting — a restored 1890 wooden depot — makes it feel like stepping into the storybook. It''s a once-a-year magical moment for preschool and early-elementary kids and absolutely worth the ticket.',
  '{"Tickets are timed and typically sell out weeks in advance — buy as soon as spring tickets drop", "~$32/person; everyone age 1 and up needs a ticket", "Plan for ~2 hours on site plus 30 min early arrival — it''s not a quick stop", "Summer in Snoqualmie can get hot with limited shade — sunscreen, hats, and water bottles are essential", "Limited food on site (snacks only) — eat in downtown Snoqualmie before or after", "Event runs rain or shine, but a miserable weather day is a miserable day for kids", "Best suited for kids age 8 and under — older kids may lose interest fast"}',
  'Buy tickets the moment they go on sale (usually late March). Book the earliest time slot of the day — crowds are lightest and the kids are freshest. Combine with lunch or ice cream at Snoqualmie Falls (~5 min drive) to turn it into a full Saturday outing. Bring a stroller that folds — train aisles are narrow.',
  '[{"name": "Snoqualmie Falls Candy Shoppe", "description": "Classic old-timey candy store in downtown Snoqualmie"}, {"name": "Black Dog Arts Cafe", "description": "Family-friendly sandwiches and salads a block from the depot"}, {"name": "Salish Lodge Dining Room", "description": "Fancy splurge at Snoqualmie Falls if you want to make it a bigger day"}, {"name": "Snoqualmie Ice Cream", "description": "Post-event treat a few minutes up the road in the same town"}]',
  '2026-07-10', '2026-07-26', 'annual',
  null
);
